import { test, expect } from '@playwright/test'

const isManual = process.env.DEMO_MODE === 'manual'

test.describe('Boot Verification', () => {
  test('API health endpoint returns OK', async ({ request }) => {
    const response = await request.get('http://localhost:8081/health')
    expect(response.ok()).toBeTruthy()
  })

  test('Home page loads', async ({ page }) => {
    await page.goto('/')
    await expect(page.getByText('Your second brain')).toBeVisible()

    if (isManual) await page.pause()
  })

  test('Login with seed credentials', async ({ page }) => {
    await page.goto('/login')
    await page.getByLabel('Email').fill('ketan@example.com')
    await page.getByLabel('Password').fill('testpassword123')
    await page.getByRole('button', { name: 'Login' }).click()

    // After login, redirects to / — verify authenticated state shows Capture button
    await expect(page.getByRole('button', { name: 'Capture' })).toBeVisible()

    if (isManual) await page.pause()
  })

  test('Browse page accessible after login', async ({ page }) => {
    // Login first
    await page.goto('/login')
    await page.getByLabel('Email').fill('ketan@example.com')
    await page.getByLabel('Password').fill('testpassword123')
    await page.getByRole('button', { name: 'Login' }).click()
    await expect(page.getByRole('button', { name: 'Capture' })).toBeVisible()

    // Navigate to browse
    await page.goto('/browse')
    await page.waitForLoadState('networkidle')

    // Verify page loaded (browse should show items or empty state)
    await expect(page).toHaveURL(/\/browse/)

    if (isManual) await page.pause()
  })
})

import { defineConfig, devices } from '@playwright/test'

const mode = (process.env.DEMO_MODE ?? 'auto') as 'auto' | 'manual' | 'headless'

const modeSettings = {
  auto: { headless: false, slowMo: 800, trace: 'on' as const },
  manual: { headless: false, slowMo: 0, trace: 'on' as const },
  headless: { headless: true, slowMo: 0, trace: 'on-first-retry' as const },
}

const settings = modeSettings[mode] ?? modeSettings.auto

export default defineConfig({
  testDir: './tests',
  fullyParallel: false,
  workers: 1,
  retries: 0,
  timeout: 30_000,

  reporter: [
    ['html', { outputFolder: '../logs/demo/report', open: 'never' }],
    ['list'],
  ],

  outputDir: '../logs/demo/artifacts',

  use: {
    baseURL: 'http://localhost:8080',
    headless: settings.headless,
    trace: settings.trace,
    ...devices['Desktop Chrome'],
    launchOptions: {
      slowMo: settings.slowMo,
    },
  },

  projects: [
    {
      name: 'boot-verification',
      testMatch: /boot-verification\.spec\.ts/,
    },
  ],
})

package testutil

