// SeedAll inserts all seed data into the database.
func SeedAll(ctx context.Context, pool *pgxpool.Pool) error {
	userIDs, err := SeedUsers(ctx, pool)
	if err != nil {
		return fmt.Errorf("testutil: seed all: %w", err)
	}

	for _, uid := range userIDs {
		if err := SeedItems(ctx, pool, uid); err != nil {
			return fmt.Errorf("testutil: seed all: %w", err)
		}
	}

	// Use the first user for MCP clients and audit log.
	clientIDs, err := SeedMCPClients(ctx, pool, userIDs[0])
	if err != nil {
		return fmt.Errorf("testutil: seed all: %w", err)
	}

	if err := SeedAuditLog(ctx, pool, userIDs[0], clientIDs[0]); err != nil {
		return fmt.Errorf("testutil: seed all: %w", err)
	}

	return nil
}

// SeedUsers creates sample users and returns their IDs.
func SeedUsers(ctx context.Context, pool *pgxpool.Pool) ([]uuid.UUID, error) {
	hash, err := bcrypt.GenerateFromPassword([]byte("testpassword123"), bcrypt.MinCost)
	if err != nil {
		return nil, fmt.Errorf("testutil: hash password: %w", err)
	}
	passwordHash := string(hash)

	users := []struct {
		email       string
		displayName string
	}{
		{"ketan@example.com", "Ketan Gangatirkar"},
		{"test@example.com", "Test User"},
		{"admin@example.com", "Admin User"},
	}

	ids := make([]uuid.UUID, 0, len(users))
	for _, u := range users {
		var id uuid.UUID
		err := pool.QueryRow(ctx,
			`INSERT INTO users (email, display_name, password_hash) VALUES ($1, $2, $3)
			 RETURNING id`,
			u.email, u.displayName, passwordHash,
		).Scan(&id)
		if err != nil {
			return nil, fmt.Errorf("testutil: insert user %s: %w", u.email, err)
		}
		ids = append(ids, id)
	}

	return ids, nil
}

